    }

    // GLOBAL OPTIONS section
    if (info.globalOptions && info.globalOptions.length > 0) {
      sections.push(this.formatSection('GLOBAL OPTIONS', this.formatOptions(info.globalOptions)));
    }

    // EXAMPLES section
